// Hide server information headers
// 1. Nginx
server_tokens off;
more_clear_headers 'Server';
more_clear_headers 'X-Powered-By';

// 2. Apache
ServerTokens Prod
Header unset X-Powered-By
Header unset Server

// 3. Express.js
app.disable('x-powered-by');
app.use((req, res, next) => {
    res.removeHeader('X-Powered-By');
    next();
});

